parameters.jsCode:
// Build the four content file payloads to write to GitHub.
// Files:
//   content/topics/{topic_slug}/{date_key}/summary.json
//   content/topics/{topic_slug}/{date_key}/article.md
//   content/topics/{topic_slug}/{date_key}/metadata.json
//   content/topics/{topic_slug}/{date_key}/video.json
//   content/topics/{topic_slug}/{date_key}/images.json  (when image_assets present)

const ctx = $input.first().json;

if (!ctx.validated) {
  throw new Error(`Attempted GitHub publish for unvalidated content: ${ctx.topic_slug}/${ctx.date_key}`);
}

const base = `content/topics/${ctx.topic_slug}/${ctx.date_key}`;
const ts = new Date().toISOString();
const youtubeMetadata = ctx.youtube_metadata || {};
const youtubeVideoId = ctx.youtube_video_id ?? null;

const summaryJson = JSON.stringify({
  topic_slug: ctx.topic_slug,
  date_key: ctx.date_key,
  generated_at: ts,
  ...ctx.summary,
  expectation_check: ctx.expectation_check,
  tomorrow_outlook: ctx.tomorrow_outlook
}, null, 2);

const metadataJson = JSON.stringify({
  topic_slug: ctx.topic_slug,
  date_key: ctx.date_key,
  alert_count: ctx.alert_count,
  cluster_count: ctx.cluster_count,
  sentiment: ctx.summary.sentiment,
  topic_score: ctx.summary.topic_score,
  generated_at: ts,
  publish_job_id: ctx.publish_job_id
}, null, 2);

// video.json exposes top-level title and video_id for the frontend VideoEmbed
// component, plus the full script and metadata for future video pipeline use.
const videoJson = JSON.stringify({
  topic_slug: ctx.topic_slug,
  date_key: ctx.date_key,
  title: youtubeMetadata.title ?? null,
  video_id: youtubeVideoId,
  script: ctx.video_script,
  youtube_metadata: youtubeMetadata,
  youtube_video_id: youtubeVideoId,
  generated_at: ts
}, null, 2);

const files = [
  {
    path: `${base}/summary.json`,
    content: summaryJson,
    message: `daily(${ctx.topic_slug}): summary for ${ctx.date_key}`
  },
  {
    path: `${base}/article.md`,
    content: ctx.article_md,
    message: `daily(${ctx.topic_slug}): article for ${ctx.date_key}`
  },
  {
    path: `${base}/metadata.json`,
    content: metadataJson,
    message: `daily(${ctx.topic_slug}): metadata for ${ctx.date_key}`
  },
  {
    path: `${base}/video.json`,
    content: videoJson,
    message: `daily(${ctx.topic_slug}): video script for ${ctx.date_key}`
  }
];

// images.json — published when image_assets are present.
// Stores the asset manifest (prompt, provider, model, count) without raw
// binary data (b64_json) or temporary URLs to keep GitHub payload small.
if (ctx.image_assets && typeof ctx.image_assets === 'object') {
  const imagesManifest = {
    topic_slug: ctx.topic_slug,
    date_key: ctx.date_key,
    image_count: ctx.image_assets.image_count,
    provider: ctx.image_assets.provider,
    model: ctx.image_assets.model,
    generated_at: ctx.image_assets.generated_at,
    images: (ctx.image_assets.images || []).map(img => ({
      index: img.index,
      prompt: img.prompt,
      revised_prompt: img.revised_prompt || null,
      provider: img.provider,
      model: img.model,
      size: img.size || null,
      format: img.format,
      // Omit url (temporary) and b64_json (too large) from GitHub storage.
      // These are available in the workflow context for the video pipeline.
      mime_type: img.mime_type || null,
      generated_at: img.generated_at
    }))
  };
  files.push({
    path: `${base}/images.json`,
    content: JSON.stringify(imagesManifest, null, 2),
    message: `daily(${ctx.topic_slug}): image assets for ${ctx.date_key}`
  });
}

// Pass context along with the files list
return [{ json: { ...ctx, _github_files: files } }];

// Expand the files list into individual items for sequential GitHub writes.
const ctx = $input.first().json;
const files = ctx._github_files || [];
return files.map(f => ({
  json: {
    _ctx_topic_slug: ctx.topic_slug,
    _ctx_date_key: ctx.date_key,
    _ctx_publish_job_id: ctx.publish_job_id,
    path: f.path,
    content: f.content,
    message: f.message
  }
}));

// Extract the SHA of the existing file if it exists (needed for updates).
// GitHub returns 404 when the file doesn't exist — that is the only safe case
// for proceeding without a SHA (i.e. creating a new file).
// Any other non-2xx status (403, 429, 500, etc.) is treated as a hard error
// so retries / errorWorkflow kick in with a clear failure rather than attempting
// a PUT that GitHub will reject with a confusing 422 conflict.
const shaResponse = $input.item.json;
const fileItem = $('Write Files One by One').item.json;

// n8n's httpRequest with ignoreResponseCode=true exposes the HTTP status code
// via the response headers or the _statusCode field.
const statusCode = shaResponse?._statusCode
  || shaResponse?.statusCode
  || (shaResponse?.message === 'Not Found' ? 404 : null)
  || (shaResponse?.sha ? 200 : null);

if (statusCode !== null && statusCode !== 200 && statusCode !== 404) {
  throw new Error(
    `Unexpected GitHub GET response (HTTP ${statusCode}) for path '${fileItem.path}'. ` +
    `Expected 200 (file exists) or 404 (file missing). ` +
    `Response: ${JSON.stringify(shaResponse).slice(0, 300)}`
  );
}

// 200 → file exists, use its SHA for the PUT
// 404 (or unknown status with no sha) → file is new, no SHA needed
const existingSha = shaResponse?.sha || null;

return [{
  json: {
    path: fileItem.path,
    content: fileItem.content,
    message: fileItem.message,
    existing_sha: existingSha,
    _ctx_topic_slug: fileItem._ctx_topic_slug,
    _ctx_date_key: fileItem._ctx_date_key,
    _ctx_publish_job_id: fileItem._ctx_publish_job_id
  }
}];

