={{ (() => {
  const body = {
    message: $json.message,
    content: Buffer.from($json.content, 'utf8').toString('base64'),
    branch: $vars.GITHUB_CONTENT_BRANCH || 'main'
  };
  if ($json.existing_sha) body.sha = $json.existing_sha;
  return body;
})() }}

