// Extract the commit SHA from the GitHub API response and pass it through.
const writeResp = $input.item.json;
const fileItem = $('Extract Existing SHA').item.json;

const commitSha = writeResp?.commit?.sha || null;

if (!commitSha) {
  throw new Error(`GitHub write did not return a commit SHA for path: ${fileItem.path}`);
}

return [{
  json: {
    path: fileItem.path,
    commit_sha: commitSha,
    _ctx_topic_slug: fileItem._ctx_topic_slug,
    _ctx_date_key: fileItem._ctx_date_key,
    _ctx_publish_job_id: fileItem._ctx_publish_job_id
  }
}];

// Collect all write results from every loop iteration.
// Use $('Extract Commit SHA').all() to reference ALL outputs accumulated across
// every SplitInBatches iteration, not just the items carried on the done path.
const results = $('Extract Commit SHA').all().map(i => i.json);
const lastCommitSha = results[results.length - 1]?.commit_sha || null;
const firstItem = results[0];

return [{
  json: {
    topic_slug: firstItem._ctx_topic_slug,
    date_key: firstItem._ctx_date_key,
    publish_job_id: firstItem._ctx_publish_job_id,
    github_commit_sha: lastCommitSha,
    files_written: results.map(r => r.path)
  }
}];
